&lt;h2&gt;&lt;a href=&#34;#level-21&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-21&#34;&gt;Level 21&lt;/span&gt;&lt;/h2&gt;&lt;blockquote&gt;
&lt;p&gt;Yes! This is really level 21 in here.&lt;br&gt;And yes, After you solve it, you&amp;apos;ll be in level 22!&lt;/p&gt;
&lt;p&gt;Now for the level:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;We used to play this game when we were kids&lt;/li&gt;
&lt;li&gt;When I had no idea what to do, I looked backwards.&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;&amp;#x538B;&amp;#x7F29;&amp;#x5305;&amp;#x5185;&amp;#x6709;&lt;code&gt;package.pack&lt;/code&gt;&amp;#x6587;&amp;#x4EF6;&amp;#xFF0C;&amp;#x5148;&amp;#x5C1D;&amp;#x8BD5;16&amp;#x8FDB;&amp;#x5236;&amp;#x6253;&amp;#x5F00;&amp;#xFF0C;&amp;#x770B;&amp;#x6587;&amp;#x4EF6;&amp;#x5934;&amp;#x4F1A;&amp;#x4E0D;&amp;#x4F1A;&amp;#x662F;&amp;#x5E38;&amp;#x89C1;&amp;#x7684;&amp;#x683C;&amp;#x5F0F;&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;assets/21/package.pack&amp;quot;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;rb&amp;apos;&lt;/span&gt;) &lt;span class=&#34;hljs-keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    data = f.read()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(data[:&lt;span class=&#34;hljs-number&#34;&gt;20&lt;/span&gt;].&lt;span class=&#34;hljs-built_in&#34;&gt;hex&lt;/span&gt;())&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
