;apos;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;rb&amp;apos;&lt;/span&gt;) &lt;span class=&#34;hljs-keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    data = f.read()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logs = []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;hljs-literal&#34;&gt;True&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; data[:&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;].&lt;span class=&#34;hljs-built_in&#34;&gt;hex&lt;/span&gt;() == &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;789c&amp;apos;&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        data = zlib.decompress(data)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        logs.append(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;*&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;elif&lt;/span&gt; data[:&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;].&lt;span class=&#34;hljs-built_in&#34;&gt;hex&lt;/span&gt;() == &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;425a&amp;quot;&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        data = bz2.decompress(data)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        logs.append(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;@&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;elif&lt;/span&gt; data[-&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;:].&lt;span class=&#34;hljs-built_in&#34;&gt;hex&lt;/span&gt;() == &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;9c78&amp;quot;&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        data = zlib.decompress(data[::-&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        logs.append(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;#&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;elif&lt;/span&gt; data[-&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;:].&lt;span class=&#34;hljs-built_in&#34;&gt;hex&lt;/span&gt;() == &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;5a42&amp;quot;&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        data = bz2.decompress(data[::-&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        logs.append(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;+&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;count = Counter(logs)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(count)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

