&lt;p&gt;OK&amp;#xFF0C;&amp;#x90A3;&amp;#x6211;&amp;#x4EEC;&amp;#x8981;&amp;#x627E;&amp;#x7684;&amp;#x50CF;&amp;#x7D20;&amp;#x503C;&amp;#x4E00;&amp;#x5171;&amp;#x6709;&amp;#x4E24;&amp;#x79CD;&amp;#x5B58;&amp;#x5728;&amp;#x5F62;&amp;#x5F0F;&amp;#xFF0C;&lt;code&gt;8&lt;/code&gt;&amp;#x4EE5;&amp;#x53CA;&lt;code&gt;(8, 8, 8)&lt;/code&gt;&amp;#x3002;&amp;#x8FD9;&amp;#x56DE;&amp;#x83B7;&amp;#x53D6;&amp;#x8FD9;&amp;#x4E9B;&amp;#x7070;&amp;#x8272;&amp;#x50CF;&amp;#x7D20;&amp;#x7684;&amp;#x5750;&amp;#x6807;&amp;#x5C31;&amp;#x5BB9;&amp;#x6613;&amp;#x591A;&amp;#x4E86;&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;from&lt;/span&gt; PIL &lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; Image, ImageSequence&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pic = Image.&lt;span class=&#34;hljs-built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;assets/white.gif&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;frames = ImageSequence.Iterator(pic)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;coords = []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; frame &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; frames:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; n_y &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;range&lt;/span&gt;(frame.size[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;]):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        pixels = [frame.getpixel((n_x, n_y)) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; n_x &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;range&lt;/span&gt;(frame.size[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;])]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            pos_x = pixels.index(&lt;span class=&#34;hljs-number&#34;&gt;8&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            pos_y = n_y&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            coords.append([pos_x, pos_y])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;hljs-keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;except&lt;/span&gt; ValueError:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                pos_x = pixels.index((&lt;span class=&#34;hljs-number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;8&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                pos_y = n_y&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                coords.append([pos_x, pos_y])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;hljs-keyword&#34;&gt;except&lt;/span&gt; ValueError:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;hljs-keyword&#34;&gt;pass&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(coords)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&lt;code&gt;coords&lt;/code&gt;&amp;#x53D8;&amp;#x91CF;&amp;#x662F;&amp;#x4E2A;&amp;#x957F;&amp;#x5EA6;&amp;#x4E3A;133&amp;#x7684;&amp;#x4E8C;&amp;#x7EF4;&amp;#x5217;&amp;#x8868;&amp;#xFF0C;&lt;code&gt;white.gif&lt;/code&gt;&amp;#x4E00;&amp;#x5171;&amp;#x6709;133&amp;#x5E27;&amp;#x3002;&amp;#x5E94;&amp;#x8BE5;&amp;#x5DF2;&amp;#x7ECF;&amp;#x83B7;&amp;#x5F97;&amp;#x4E86;&amp;#x6240;&amp;#x6709;&amp;#x7684;&amp;#x5750;&amp;#x6807;&amp;#x4E86;&amp;#x3002;&amp;#x4ED4;&amp;#x7EC6;&amp;#x770B;&amp;#x4E00;&amp;#x4E0B;&amp;#x8FD9;&amp;#x4E9B;&amp;#x5750;&amp;#x6807;&amp;#xFF0C;&amp;#x6240;&amp;#x6709;&amp;#x5750;&amp;#x6807;&amp;#x503C;&amp;#x90FD;&amp;#x5728;&amp;#x70B9;(100, 100)&amp;#x5468;&amp;#x56F4;&amp;#x4E24;&amp;#x4E2A;&amp;#x50CF;&amp;#x7D20;&amp;#x5185;&amp;#x3002;&amp;#x54E6;&amp;#x5BF9;&amp;#x4E86;&amp;#xFF0C;&lt;code&gt;copper.html&lt;/code&gt;&amp;#x9875;&amp;#x9762;&amp;#x4E0A;&amp;#x7684;&amp;#x56FE;&amp;#x7247;&amp;#x770B;&amp;#x4E0A;&amp;#x53BB;&amp;#x5E94;&amp;#x8BE5;&amp;#x662F;&amp;#x4E2A;&amp;#x65B9;&amp;#x5411;&amp;#x64CD;&amp;#x7EB5;&amp;#x6746;&amp;#xFF0C;&amp;#x6216;&amp;#x8BB8;&amp;#x8FD9;&amp;#x4E9B;&amp;#x5750;&amp;#x6807;&amp;#x5206;&amp;#x522B;&amp;#x4EE3;&amp;#x8868;&amp;#x4E00;&amp;#x4E2A;&amp;#x65B9;&amp;#x5411;&amp;#xFF1F;&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;newpic = Image.new(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;1&amp;quot;&lt;/span&gt;, (&lt;span class=&#34;hljs-number&#34;&gt;1000&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;100&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;px = py = &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; coord &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; coords:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    x = coord[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;] - &lt;span class=&#34;hljs-number&#34;&gt;100&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    y = coord[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;] - &lt;span class=&#34;hljs-number&#34;&gt;100&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; x == y == &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        x += &lt;span class=&#34;hljs-number&#34;&gt;100&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    px += x&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    py += y&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    newpic.putpixel((px, py), &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;newpic.show()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

