34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Ornhgvshy vf orggre guna htyl.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Rkcyvpvg vf orggre guna vzcyvpvg.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Fvzcyr vf orggre guna pbzcyrk.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Pbzcyrk vf orggre guna pbzcyvpngrq.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Syng vf orggre guna arfgrq.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Fcnefr vf orggre guna qrafr.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Ernqnovyvgl pbhagf.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Fcrpvny pnfrf nera&amp;apos;g fcrpvny rabhtu gb oernx gur ehyrf.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Nygubhtu cenpgvpnyvgl orngf chevgl.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Reebef fubhyq arire cnff fvyragyl.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Hayrff rkcyvpvgyl fvyraprq.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Va gur snpr bs nzovthvgl, ershfr gur grzcgngvba gb thrff.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Gurer fubhyq or bar-- naq cersrenoyl bayl bar --boivbhf jnl gb qb vg.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Nygubhtu gung jnl znl abg or boivbhf ng svefg hayrff lbh&amp;apos;er Qhgpu.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Abj vf orggre guna arire.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Nygubhtu arire vf bsgra orggre guna *evtug* abj.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Vs gur vzcyrzragngvba vf uneq gb rkcynva, vg&amp;apos;f n onq vqrn.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Vs gur vzcyrzragngvba vf rnfl gb rkcynva, vg znl or n tbbq vqrn.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-string&#34;&gt;Anzrfcnprf ner bar ubaxvat terng vqrn -- yrg&amp;apos;f qb zber bs gubfr!&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;d = {}&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; c &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; (&lt;span class=&#34;hljs-number&#34;&gt;65&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;97&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;26&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        d[&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(i+c)] = &lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;((i+&lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;) % &lt;span class=&#34;hljs-number&#34;&gt;26&lt;/span&gt; + c)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join([d.get(c, c) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; c &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; s]))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&amp;#x9700;&amp;#x8981;&amp;#x5148;&amp;#x5BF9;&amp;#x6240;&amp;#x6709;&amp;#x5B57;&amp;#x6BCD;&amp;#x8FDB;&amp;#x884C;ascii&amp;#x7801;&amp;#x5E73;&amp;#x79FB;&amp;#x624D;&amp;#x80FD;&amp;#x89E3;&amp;#x5BC6;&amp;#x8FD9;&amp;#x9996;&amp;#x8BD7;&amp;#x3002;&amp;#x90A3;&amp;#xFF0C;&amp;#x6211;&amp;#x4EEC;&amp;#x8BD5;&amp;#x8BD5;&amp;#x5BF9;&lt;code&gt;&amp;apos;va gur snpr bs jung&amp;apos;&lt;/code&gt;&amp;#x8FDB;&amp;#x884C;&amp;#x76F8;&amp;#x540C;&amp;#x7684;&amp;#x5904;&amp;#x7406;&amp;#x8BD5;&amp;#x8BD5;&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;s = &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;va gur snpr bs jung&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;d = {}&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; c &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; (&lt;span class=&#34;hljs-number&#34;&gt;65&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;97&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;26&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        d[&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(i+c)] = &lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;((i+&lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;) % &lt;span class=&#34;hljs-number&#34;&gt;26&lt;/span&gt; + c)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join([d.get(c, c) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; c &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; s]))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt