&lt;h2&gt;&lt;a href=&#34;#level-0&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-0&#34;&gt;Level 0&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;2&lt;sup&gt;38&lt;/sup&gt;=274877906944&lt;/p&gt;
&lt;p&gt;Change the url to &lt;a href=&#34;http://www.pythonchallenge.com/pc/def/274877906944.html&#34;&gt;http://www.pythonchallenge.com/pc/def/274877906944.html&lt;/a&gt;&amp;#xFF0C;and there comes Level 1.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#level-1&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-1&#34;&gt;Level 1&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;Obviously, by adding an offset to the ascii of each letter in the sentence you&amp;apos;ll get the instruction.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;line = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;g fmnc wms bgblr rpylqjyrc gr zw fylb. rfyrq ufyr amknsrcpq ypc dmp. bmgle gr gl zw fylb gq glcddgagclr ylb rfyr&amp;apos;q ufw rfgq rcvr gq qm jmle. sqgle qrpgle.kyicrpylq() gq pcamkkclbcb. lmu ynnjw ml rfc spj.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;list1 = []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;list&lt;/span&gt;(line):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; i.isalpha():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        j = &lt;span class=&#34;hljs-built_in&#34;&gt;ord&lt;/span&gt;(i)+&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        s = &lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(j) &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; j&amp;lt;&lt;span class=&#34;hljs-number&#34;&gt;123&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(j-&lt;span class=&#34;hljs-number&#34;&gt;26&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        s = i&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    list1.append(s)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join(list1))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;The output&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;i hope you didnt translate it by hand. thats what computers are for. doing it in by hand is inefficient and that&amp;apos;s why this text is so long. using string.maketrans() is recommended. now apply on the url.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;OK, apply to the url &lt;code&gt;map&lt;/code&gt;, and the url for level 2 is here.&lt;/p&gt;
&lt;p&gt;Noted that it mentioned &lt;code&gt;str.maketrans()&lt;/code&gt; function, which is not how I solved the problem. So what does &lt;code&gt;maketrans()&lt;/code&gt; do? Here is the &lt;a href=&#34;https://docs.python.org/3/library/stdtypes.html?highlight=maketrans#str.maketrans&#34;&gt;official documentation&lt;/a&gt;. In short, it generates a translating method. &lt;code&gt;str.translate()&lt;/code&gt; function then uses this method to translate a giving string. Now let&amp;apos;s try this out.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;line = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;g fmnc wms bgblr rpylqjyrc gr zw fylb. rfyrq ufyr amknsrcpq ypc dmp. bmgle gr gl zw fylb gq glcddgagclr ylb rfyr&amp;apos;q ufw rfgq rcvr gq qm jmle. sqgle qrpgle.kyicrpylq() gq pcamkkclbcb. lmu ynnjw ml rfc spj.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;label1 = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;abcdefghijklmnopqrstuvwxyz&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;label2 = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;cdefghijklmnopqrstuvwxyzab&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;trans = &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;.maketrans(label1, label2)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;line&amp;quot;&lt;/span&gt;.translate(trans))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;i hope you didnt translate it by hand. thats what computers are for. doing it in by hand is inefficient and that&amp;apos;s why this text is so long. using string.maketrans() is recommended. now apply on the url.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;OK, exactly what we expected.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#level-2&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-2&#34;&gt;Level 2&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;It&amp;apos;s evident that we should take a look at the source code of the page. There&amp;apos;s a comment: &lt;code&gt;find rare charactors below&lt;/code&gt;.&lt;/p&gt;
&lt;p&gt;For convenience, save all those charactors to &lt;code&gt;assets/txt_for_2.txt&lt;/code&gt;, and find out the occurrance of each charactor.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;from&lt;/span&gt; collections &lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; Counter&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;assets/txt_for_2.txt&amp;quot;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;r&amp;quot;&lt;/span&gt;) &lt;span class=&#34;hljs-keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    string = f.read()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;count = Counter(string)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(count)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;Counter({&amp;apos;)&amp;apos;: 6186, &amp;apos;@&amp;apos;: 6157, &amp;apos;(&amp;apos;: 6154, &amp;apos;]&amp;apos;: 6152, &amp;apos;#&amp;apos;: 6115, &amp;apos;_&amp;apos;: 6112, &amp;apos;[&amp;apos;: 6108, &amp;apos;}&amp;apos;: 6105, &amp;apos;%&amp;apos;: 6104, &amp;apos;!&amp;apos;: 6079, &amp;apos;+&amp;apos;: 6066, &amp;apos;$&amp;apos;: 6046, &amp;apos;{&amp;apos;: 6046, &amp;apos;&amp;amp;&amp;apos;: 6043, &amp;apos;*&amp;apos;: 6034, &amp;apos;^&amp;apos;: 6030, &amp;apos;\n&amp;apos;: 1219, &amp;apos;e&amp;apos;: 1, &amp;apos;q&amp;apos;: 1, &amp;apos;u&amp;apos;: 1, &amp;apos;a&amp;apos;: 1, &amp;apos;l&amp;apos;: 1, &amp;apos;i&amp;apos;: 1, &amp;apos;t&amp;apos;: 1, &amp;apos;y&amp;apos;: 1})&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;OK, combine the charactors only show up once, and there you get the url for next level.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#level-3&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-3&#34;&gt;Level 3&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;Again, obviously, this level demands regx. Taking a look at the source code is a must. Save those charactors to &lt;code&gt;assets/txt_for_3.txt&lt;/code&gt; and let&amp;apos;s go for it.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; re&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;assets/txt_for_3.txt&amp;quot;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;r&amp;quot;&lt;/span&gt;) &lt;span class=&#34;hljs-keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    line = f.read()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;reg=re.&lt;span class=&#34;hljs-built_in&#34;&gt;compile&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;[a-z][A-Z]{3}[a-z][A-Z]{3}[a-z]&amp;apos;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;url = reg.findall(line)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; u &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; url:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(u[&lt;span class=&#34;hljs-number&#34;&gt;4&lt;/span&gt;], end=&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;&amp;apos;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;And the output is &lt;code&gt;linkedlist&lt;/code&gt;, now change the url. The url for the next level is a little different, as it says.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#level-4&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-4&#34;&gt;Level 4&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;Nothing on the page or in the source code. Click on the image, it leads us to a new page and says &lt;code&gt;the next nothing is 44827&lt;/code&gt;.&lt;/p&gt;
&lt;p&gt;Change the url to &lt;code&gt;...?nothing=44827&lt;/code&gt;. Oh, again, &lt;code&gt;the next nothing is 45439&lt;/code&gt;. Seems that some http library like &lt;code&gt;requests&lt;/code&gt; is needed.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; requests&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;url=&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;http://www.pythonchallenge.com/pc/def/linkedlist.php?nothing=12345&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;r=requests.get(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;txt=r.text&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;hljs-literal&#34;&gt;True&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    url=&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;http://www.pythonchallenge.com/pc/def/linkedlist.php?nothing=&amp;apos;&lt;/span&gt;+txt.split()[-&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    r=requests.get(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    txt=r.text&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(txt)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;Wait for a reasonable output.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#level-5&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-5&#34;&gt;Level 5&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;pronouce it.&lt;/p&gt;
&lt;p&gt;Go for source code. The image is called &lt;code&gt;peakhell.jpg&lt;/code&gt;. And there&amp;apos;s something didn&amp;apos;t show up on the page.&lt;/p&gt;
&lt;figure class=&#34;highlight html hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-tag&#34;&gt;&amp;lt;&lt;span class=&#34;hljs-name&#34;&gt;peakhell&lt;/span&gt; &lt;span class=&#34;hljs-attr&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;banner.p&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;&amp;lt;!-- peak hell sounds familiar ? --&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-tag&#34;&gt;&amp;lt;/&lt;span class=&#34;hljs-name&#34;&gt;peakhell&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;Changing url to &lt;code&gt;banner.p&lt;/code&gt;, there&amp;apos;s a load of charactors making no sense at all.&lt;/p&gt;
&lt;p&gt;Back to where we started, &amp;quot;pronounce it&amp;quot;. There&amp;apos;s a module called &lt;a href=&#34;https://docs.python.org/3/library/pickle.html&#34;&gt;&lt;code&gt;pickle&lt;/code&gt;&lt;/a&gt; which is for serializing and de-serializing.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;from&lt;/span&gt; urllib &lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; request&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; pickle&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;url = &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;http://www.pythonchallenge.com/pc/def/banner.p&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;f = request.urlopen(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;result = pickle.load(f)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(result)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;The output turns out to be a two-dimensional list. Take a glance at it. The numbers in the first three lines add up to 95. There&amp;apos;s a possibility that the number is the occurrance of the charactor in front.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; result:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; j &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; i:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(j[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;] * j[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;], end = &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;&amp;apos;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;\n&amp;apos;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;The output is&lt;/p&gt;
&lt;img src=&#34;/img/level5.png&#34; alt=&#34;channel by # charactor&#34; width=&#34;300px&#34;&gt;

&lt;h2&gt;&lt;a href=&#34;#level-6&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-6&#34;&gt;Level 6&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;zip&lt;/p&gt;
&lt;p&gt;Change the url to &lt;code&gt;*.zip&lt;/code&gt; and we get a file &lt;code&gt;channel.zip&lt;/code&gt;. Unzip it, there&amp;apos;s a &lt;code&gt;readme.txt&lt;/code&gt;. Well, it&amp;apos;s similiar to level 4.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;PATH = &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;assets/channel/&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;name = &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;90052&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;hljs-literal&#34;&gt;True&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    filepath = PATH + name + &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;.txt&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;open&lt;/span&gt;(filepath, &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;r&amp;quot;&lt;/span&gt;) &lt;span class=&#34;hljs-keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        text = f.readline()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(text)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        s = text.split(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot; &amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        name = s[-&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;NO, the programe runs into an error. In the last file&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;collect the comments.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;Now, what is a zip comment? Google it:&lt;br&gt;A comment is optional text information that is embedded in a Zip file.  -&amp;gt;&lt;a href=&#34;https://kb.winzip.com/help/help_comment.htm#:~:text=Zip%20file%20comments%20A%20comment%20is%20optional%20text,created%2C%20edited%2C%20or%20deleted%20using%20the%20Comment%20window.&#34;&gt;source&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;With 7zip, we can see the comment of each file. The lengths of those comments are the same, only one charactor. Now, let&amp;apos;s have fun with the zip file. &lt;a href=&#34;https://docs.python.org/3/library/zipfile.html&#34;&gt;&lt;code&gt;zipfile&lt;/code&gt;&lt;/a&gt; module is needed, of course.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; zipfile&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;num = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;90052&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;comments = []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;f = zipfile.ZipFile(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;assets/channel.zip&amp;quot;&lt;/span&gt;)   &lt;span class=&#34;hljs-comment&#34;&gt;# open zip file&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;hljs-literal&#34;&gt;True&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        filepath = num + &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;.txt&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        line = f.read(filepath).decode(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;utf-8&amp;quot;&lt;/span&gt;) &lt;span class=&#34;hljs-comment&#34;&gt;# read txt file inside&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        comment = f.getinfo(filepath).comment.decode(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;utf-8&amp;quot;&lt;/span&gt;)     &lt;span class=&#34;hljs-comment&#34;&gt;# comment of txt file&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        num = line.split(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot; &amp;quot;&lt;/span&gt;)[-&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        comments.append(comment)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;except&lt;/span&gt; KeyError:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join(comments))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;img src=&#34;/img/level6.png&#34; alt=&#34;level6&#34; width=&#34;300px&#34;&gt;

&lt;p&gt;Replace the url with &lt;code&gt;hockey&lt;/code&gt;. It says &lt;code&gt;it&amp;apos;s in the air. look at the letters.&lt;/code&gt; Well, ya know what to do.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#level-7&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-7&#34;&gt;Level 7&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;Just a picture, nothing in the source code. The information has to be in the picture, then.&lt;/p&gt;
&lt;p&gt;Noted there&amp;apos;s a horizontal line which does not fit the picture at all. By observing the line pixel by pixel with Snipaste, we can find out that the color turns different every 7-9 pixels.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; cv2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img = cv2.imread(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;assets/oxygen.png&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;offset1, offset2, offset3 = &lt;span class=&#34;hljs-number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;9&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x, y, z, m = &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;, &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;(img.shape[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;] / &lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt; + &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;l1, l2, l3 = [], [], []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; x &amp;lt;= img.shape[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    px1 = img[m, x]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; px1[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;] == px1[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;] == px1[&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        l1.append(px1[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    x += offset1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; y &amp;lt;= img.shape[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    px2 = img[m, y]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; px2[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;] == px2[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;] == px2[&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        l2.append(px2[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    y += offset2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; z &amp;lt;= img.shape[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    px3 = img[m, z]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; px3[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;] == px3[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;] == px3[&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        l3.append(px3[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    z += offset3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;f&amp;quot;offset = 7: &lt;span class=&#34;hljs-subst&#34;&gt;{l1}&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;f&amp;quot;offset = 8: &lt;span class=&#34;hljs-subst&#34;&gt;{l2}&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;f&amp;quot;offset = 9: &lt;span class=&#34;hljs-subst&#34;&gt;{l3}&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;offset = 7: [115, 109, 97, 114, 116, 32, 103, 117, 121, 44, 32, 121, 111, 117, 32, 109, 97, 100, 101, 32, 105, 116, 46, 32, 116, 104, 101, 32, 110, 101, 120, 116, 32, 108, 101, 118, 101, 108, 32, 105, 115, 32, 91, 49, 48, 53, 44, 32, 49, 49, 48, 44, 32, 49, 49, 54, 44, 32, 49, 48, 49, 44, 32, 49, 48, 51, 44, 32, 49, 49, 52, 44, 32, 49, 48, 53, 44, 32, 49, 49, 54, 44, 32, 49, 50, 49, 93]&lt;br&gt;offset = 8: [115, 109, 97, 114, 116, 103, 117, 121, 44, 32, 121, 111, 32, 109, 97, 100, 101, 32, 105, 46, 32, 116, 104, 101, 32, 110, 120, 116, 32, 108, 101, 118, 101, 32, 105, 115, 32, 91, 49, 48, 44, 32, 49, 49, 48, 44, 32, 49, 54, 44, 32, 49, 48, 49, 32, 49, 48, 51, 44, 32, 49, 52, 44, 32, 49, 48, 53, 44, 49, 49, 54, 44, 32, 49, 50, 93]&lt;br&gt;offset = 9: [115, 109, 97, 116, 32, 103, 121, 44, 32, 121, 117, 32, 109, 100, 101, 32, 105, 46, 32, 116, 101, 32, 110, 101, 116, 32, 108, 118, 101, 108, 32, 115, 32, 91, 48, 53, 44, 32, 49, 48, 44, 49, 49, 54, 44, 49, 48, 49, 32, 49, 48, 51, 32, 49, 49, 44, 32, 49, 48, 44, 32, 49, 54, 44, 32, 49, 49, 93]&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;Translate these numbers as ascii code&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;s1 = [&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(i) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; l1]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s2 = [&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(i) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; l2]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;s3 = [&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(i) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; l3]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;f&amp;quot;offset = 7: &lt;span class=&#34;hljs-subst&#34;&gt;{&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;&amp;apos;&lt;/span&gt;.join(s1)}&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;f&amp;quot;offset = 8: &lt;span class=&#34;hljs-subst&#34;&gt;{&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;&amp;apos;&lt;/span&gt;.join(s2)}&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;f&amp;quot;offset = 9: &lt;span class=&#34;hljs-subst&#34;&gt;{&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;&amp;apos;&lt;/span&gt;.join(s3)}&lt;/span&gt;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;offset = 7: smart guy, you made it. the next level is [105, 110, 116, 101, 103, 114, 105, 116, 121]&lt;br&gt;offset = 8: smartguy, yo made i. the nxt leve is [10, 110, 16, 101 103, 14, 105,116, 12]&lt;br&gt;offset = 9: smat gy, yu mde i. te net lvel s [05, 10,116,101 103 11, 10, 16, 11]&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;It&amp;apos;s obvious that result under &lt;code&gt;offset=7&lt;/code&gt; makes sense. Now do the same thing to the numbers in the result.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#level-8&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-8&#34;&gt;level 8&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;There&amp;apos;s a link on the body of the bee. And it leads us to a site which requires logging in. Source code! of course.&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;un: &amp;apos;BZh91AY&amp;amp;SYA\xaf\x82\r\x00\x00\x01\x01\x80\x02\xc0\x02\x00 \x00!\x9ah3M\x07&amp;lt;]\xc9\x14\xe1BA\x06\xbe\x084&amp;apos;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pw: &amp;apos;BZh91AY&amp;amp;SY\x94$|\x0e\x00\x00\x00\x81\x00\x03$ \x00!\x9ah3M\x13&amp;lt;]\xc9\x14\xe1BBP\x91\xf08&amp;apos;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&lt;code&gt;un&lt;/code&gt; stands for &lt;code&gt;user name&lt;/code&gt;, &lt;code&gt;pw&lt;/code&gt; for &lt;code&gt;password&lt;/code&gt;, of course. These charactors are compressed by bzip2. Let&amp;apos;s de-compress it.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; bz2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;l1 =  &lt;span class=&#34;hljs-string&#34;&gt;b&amp;apos;BZh91AY&amp;amp;SYA\xaf\x82\r\x00\x00\x01\x01\x80\x02\xc0\x02\x00 \x00!\x9ah3M\x07&amp;lt;]\xc9\x14\xe1BA\x06\xbe\x084&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;l2 =  &lt;span class=&#34;hljs-string&#34;&gt;b&amp;apos;BZh91AY&amp;amp;SY\x94$|\x0e\x00\x00\x00\x81\x00\x03$ \x00!\x9ah3M\x13&amp;lt;]\xc9\x14\xe1BBP\x91\xf08&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(bz2.decompress(l1))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(bz2.decompress(l2))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;blockquote&gt;
&lt;p&gt;b&amp;apos;huge&amp;apos;&lt;br&gt;b&amp;apos;file&amp;apos;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2&gt;&lt;a href=&#34;#level-9&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;level-9&#34;&gt;Level 9&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;The page is called &lt;code&gt;connect the dots&lt;/code&gt;, and there lies an interesting comment, &lt;code&gt;first+second=?&lt;/code&gt; followed by a bunch of numbers. Maybe these numbers are coordinates?&lt;/p&gt;
