34;&gt;0&lt;/span&gt;, &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; i &amp;lt; &lt;span class=&#34;hljs-built_in&#34;&gt;len&lt;/span&gt;(c1):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;while&lt;/span&gt; j &amp;lt; &lt;span class=&#34;hljs-built_in&#34;&gt;len&lt;/span&gt;(c1):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; c1[i] == c1[j]:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                count += &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                j += &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;hljs-keyword&#34;&gt;break&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        c2 += &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;(count) + c1[i]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        i = j&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        count = &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    a.append(c2)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    c1 = c2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    c2 = &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-built_in&#34;&gt;len&lt;/span&gt;(a[&lt;span class=&#34;hljs-number&#34;&gt;30&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

