&lt;p&gt;&amp;#x4E0A;&amp;#x56FE;&amp;#x4E3A;&amp;#x672C;&amp;#x9898;&amp;#x4E3B;&amp;#x56FE;&lt;code&gt;unreal.jpg&lt;/code&gt;&amp;#x7684;&amp;#x54CD;&amp;#x5E94;&amp;#x5934;&amp;#xFF0C;&amp;#x8868;&amp;#x793A;&amp;#x5F53;&amp;#x524D;&amp;#x6587;&amp;#x4EF6;&amp;#x7684;&amp;#x8303;&amp;#x56F4;&amp;#xFF0C;&amp;#x4FEE;&amp;#x6539;&amp;#x8BF7;&amp;#x6C42;&amp;#x5934;&amp;#x4E2D;&amp;#x7684;&lt;code&gt;Range&lt;/code&gt;&amp;#x503C;&amp;#x5373;&amp;#x53EF;&amp;#x8BBF;&amp;#x95EE;&amp;#x5176;&amp;#x4ED6;&amp;#x8303;&amp;#x56F4;&amp;#x7684;&amp;#x6587;&amp;#x4EF6;&lt;/p&gt;
&lt;p&gt;&amp;#x73B0;&amp;#x5728;&amp;#x5DF2;&amp;#x7ECF;&amp;#x77E5;&amp;#x9053;0-30202&amp;#x533A;&amp;#x95F4;&amp;#x4E3A;&amp;#x56FE;&amp;#x7247;&lt;code&gt;unreal.jpg&lt;/code&gt;&amp;#xFF0C;&amp;#x7EE7;&amp;#x7EED;&amp;#x8BBF;&amp;#x95EE;&amp;#x4E0B;&amp;#x4E00;&amp;#x6BB5;&amp;#x3002;&amp;#x8BBE;&amp;#x7F6E;&lt;code&gt;Range&lt;/code&gt;&amp;#x503C;&amp;#x4E3A;&lt;code&gt;bytes=30203-&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; requests, base64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;url = &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;http://www.pythonchallenge.com/pc/hex/unreal.jpg&amp;apos;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cred = base64.b64encode(&lt;span class=&#34;hljs-string&#34;&gt;b&amp;quot;butter:fly&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;requests.auth.HTTPBasicAuth(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;butter&amp;quot;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;fly&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;headers = {&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;Authorization&amp;apos;&lt;/span&gt;: &lt;span class=&#34;hljs-string&#34;&gt;f&amp;quot;Basic &lt;span class=&#34;hljs-subst&#34;&gt;{cred.decode()}&lt;/span&gt;&amp;quot;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;Range&amp;apos;&lt;/span&gt;:&lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;bytes=30203-&amp;apos;&lt;/span&gt;}&lt;/span&gt;&lt;br&