&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&amp;#x5E94;&amp;#x7528;&amp;#x5217;&amp;#x8868;&amp;#x9690;&amp;#x85CF;&lt;/p&gt;
&lt;p&gt; &amp;#x4E5F;&amp;#x662F;&amp;#x5237;&amp;#x673A;&amp;#x73A9;&amp;#x5BB6;&amp;#x7684;&amp;#x8001;&amp;#x670B;&amp;#x53CB;&amp;#x4E86;&amp;#xFF0C;&amp;#x4E3B;&amp;#x8981;&amp;#x662F;&amp;#x4E3A;&amp;#x4E86;&amp;#x907F;&amp;#x514D;&amp;#x5E94;&amp;#x7528;&amp;#x8BFB;&amp;#x53D6;&amp;#x5DF2;&amp;#x5B89;&amp;#x88C5;&amp;#x5E94;&amp;#x7528;&amp;#x5217;&amp;#x8868;&amp;#x4ECE;&amp;#x800C;&amp;#x751F;&amp;#x6210;&amp;#x7528;&amp;#x6237;&amp;#x753B;&amp;#x50CF;&amp;#xFF0C;&amp;#x4E00;&amp;#x5B9A;&amp;#x7A0B;&amp;#x5EA6;&amp;#x4E0A;&amp;#x4E5F;&amp;#x662F;&amp;#x9690;&amp;#x79C1;&amp;#x4FDD;&amp;#x62A4;&amp;#x7684;&amp;#x4E00;&amp;#x79CD;&amp;#x65B9;&amp;#x5F0F;&amp;#x3002;&lt;/p&gt;
&lt;p&gt; &amp;#x6E90;&amp;#x4ED3;&amp;#x5E93;&amp;#x5730;&amp;#x5740;&amp;#xFF1A;&lt;a href=&#34;https://github.com/Dr-TSNG/Hide-My-Applist&#34;&gt;github&lt;/a&gt;&amp;#xFF0C;&amp;#x8FD9;&amp;#x9879;&amp;#x529F;&amp;#x80FD;&amp;#x8981;&amp;#x4ECE;LSPosed&amp;#x4E2D;&amp;#x5B89;&amp;#x88C5;&amp;#xFF0C;&amp;#x6309;&amp;#x7167;&amp;#x8981;&amp;#x6C42;&amp;#x4E00;&amp;#x6B65;&amp;#x6B65;&amp;#x4E0B;&amp;#x8F7D;apk&amp;#x5B89;&amp;#x88C5;&amp;#xFF0C;&amp;#x5E76;&amp;#x4ECE;&amp;#x8F6F;&amp;#x4EF6;&amp;#x4E2D;&amp;#x5B89;&amp;#x88C5;&amp;#x9700;&amp;#x8981;&amp;#x7684;magisk&amp;#x6A21;&amp;#x5757;&amp;#xFF0C;&amp;#x8BBE;&amp;#x5B9A;&amp;#x767D;/&amp;#x9ED1;&amp;#x540D;&amp;#x5355;&amp;#x5E76;&amp;#x5C06;&amp;#x89C4;&amp;#x5219;&amp;#x4F5C;&amp;#x7528;&amp;#x4E8E;&amp;#x5E94;&amp;#x7528;&amp;#x5373;&amp;#x53EF;&amp;#x3002;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&amp;#x66F4;&amp;#x65B9;&amp;#x4FBF;&amp;#x7684;&amp;#x8054;&amp;#x7F51;&amp;#x63A7;&amp;#x5236;&lt;/p&gt;
&lt;p&gt; &amp;#x76F8;&amp;#x6BD4;&amp;#x4E8E;&amp;#x5B89;&amp;#x5353;&amp;#x81EA;&amp;#x5E26;&amp;#x7684;&amp;#x8054;&amp;#x7F51;&amp;#x63A7;&amp;#x5236;&amp;#x9700;&amp;#x8981;&amp;#x4E00;&amp;#x4E2A;&amp;#x4E00;&amp;#x4E2A;&amp;#x8F6F;&amp;#x4EF6;&amp;#x5730;&amp;#x8FDB;&amp;#x884C;&amp;#x7BA1;&amp;#x7406;&amp;#xFF0C;&amp;#x5229;&amp;#x7528;&lt;a href=&#34;https://github.com/ukanth/afwall/&#34;&gt;AFWall+&lt;/a&gt;&amp;#x8FDB;&amp;#x884C;&amp;#x8054;&amp;#x7F51;&amp;#x63A7;&amp;#x5236;&amp;#x5C31;&amp;#x5BB9;&amp;#x6613;&amp;#x4E14;&amp;#x6E05;&amp;#x6670;&amp;#x5F97;&amp;#x591A;&amp;#x4E86;&amp;#x3002;&amp;#x8FD9;&amp;#x662F;&amp;#x4E00;&amp;#x4E2A;&amp;#x53EF;&amp;#x4EE5;&amp;#x4ECE;Google Play&amp;#x76F4;&amp;#x63A5;&amp;#x83B7;&amp;#x53D6;&amp;#x7684;&amp;#x5E94;&amp;#x7528;&amp;#x3002;&amp;#x4F7F;&amp;#x7528;&amp;#x4E5F;&amp;#x975E;&amp;#x5E38;&amp;#x76F4;&amp;#x89C2;&amp;#xFF0C;&amp;#x52FE;&amp;#x9009;&amp;#x60F3;&amp;#x8981;&amp;#x9650;&amp;#x5236;&amp;#x7684;&amp;#x8054;&amp;#x7F51;&amp;#x529F;&amp;#x80FD;&amp;#xFF08;&amp;#x5C40;&amp;#x57DF;&amp;#x7F51;&amp;#x3001;WiFi&amp;#x3001;&amp;#x79FB;&amp;#x52A8;&amp;#x6570;&amp;#x636E;&amp;#xFF09;&amp;#xFF0C;&amp;#x518D;&amp;#x70B9;&amp;#x51FB;&amp;#x53F3;&amp;#x4E0A;&amp;#x89D2;&amp;#x5E94;&amp;#x7528;&amp;#x89C4;&amp;#x5219;&amp;#x5373;&amp;#x53EF;&amp;#x3002;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;For some unknown reasons, the ipv6 got offline once in a while. After rebooting, it turned just fine. I need ipv6 to do torrenting. So here comes the demand for a script to check my ipv6 availability.&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;figure class=&#34;highlight shell hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;!/bin/sh&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;ipv6 check script, reboot &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; fails&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;url=&amp;lt;an ipv6-only site&amp;gt;  || delete the &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;#&amp;quot;&lt;/span&gt; to take effect or replace &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;$url&amp;apos;&lt;/span&gt; with actual url down &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; the corresponding &lt;span class=&#34;hljs-built_in&#34;&gt;command&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;n=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;timeout=1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;check BEGIN&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ping -c $n -W $timeout $url&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if [ $? != 0 ];then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;failed, try reboot&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    reboot&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;working fine!&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;exit 0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;What it does is obvious. Noted that &lt;code&gt;logger -t&lt;/code&gt; needs two strings to display information in the log area. The script above displays informations as follows.&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Oct 21 17:40:00 [ipv6]:  check BEGIN&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Oct 21 17:40:03 [ipv6]:  working fine&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;However, the log area could be filled with these two information, which is not ideal. &lt;code&gt;logger -t&lt;/code&gt; sentence could be deleted after testing.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#settings&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;settings&#34;&gt;Settings&lt;/span&gt;&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;&lt;p&gt;Check &lt;code&gt;Advaced settings&lt;/code&gt;-&lt;code&gt;System settings&lt;/code&gt;-&lt;code&gt;Services&lt;/code&gt;-&lt;code&gt;Enable SSH&lt;/code&gt;. SSH might not work properly on windows due to some reason about porting. Open the corresponding ports on windows should be the solution here.&lt;/p&gt;
 &lt;figure class=&#34;highlight bash hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ssh admin@192.168.123.1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;Change directory to &lt;code&gt;/etc/storage/&lt;/code&gt;. Files in other directories will be deleted after rebooting. We don&amp;apos;t want our script to vanish, of course.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;code&gt;vi ipv6_check.sh&lt;/code&gt;. Create a .sh script, and save the code above inside. The operations of vi is somewhat different from how we operate on windows.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;The script is not written into the ROM if you did not run the mtd_storage script, because of some settings of Padavan firmware.&lt;br&gt; run &lt;code&gt;/sbin/mtd_storage.sh save&lt;/code&gt; to save the modification.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;Run script ragularly.&lt;br&gt; &lt;code&gt;system settings&lt;/code&gt;-&lt;code&gt;Services&lt;/code&gt;-&lt;code&gt;cron&lt;/code&gt;&lt;br&gt; Input &lt;code&gt;*/10 * * * * /etc/storage/ipv6_check.sh&lt;/code&gt; in the Cron tab to run the script every 10 minutes.&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;&amp;#x4E0D;&amp;#x77E5;&amp;#x9053;&amp;#x4EC0;&amp;#x4E48;&amp;#x539F;&amp;#x56E0;&amp;#xFF0C;ipv6&amp;#x603B;&amp;#x662F;&amp;#x9694;&amp;#x4E00;&amp;#x6BB5;&amp;#x65F6;&amp;#x95F4;&amp;#x5C31;&amp;#x6389;&amp;#x7EBF;&amp;#xFF0C;&amp;#x91CD;&amp;#x542F;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;&amp;#x540E;&amp;#x53C8;&amp;#x6062;&amp;#x590D;&amp;#x6B63;&amp;#x5E38;&amp;#x3002;&amp;#x53C8;&amp;#x56E0;&amp;#x4E3A;&amp;#x4E2A;&amp;#x4EBA;&amp;#x6709;pt&amp;#x505A;&amp;#x79CD;&amp;#x9700;&amp;#x6C42;&amp;#xFF0C;ipv6&amp;#x53C8;&amp;#x662F;&amp;#x4E0D;&amp;#x53EF;&amp;#x6216;&amp;#x7F3A;&amp;#x7684;&amp;#x6761;&amp;#x4EF6;&amp;#xFF0C;&amp;#x6240;&amp;#x4EE5;&amp;#x5199;&amp;#x4E2A;&amp;#x7B80;&amp;#x5355;&amp;#x7684;&amp;#x811A;&amp;#x672C;&amp;#xFF0C;&amp;#x5F53;ipv6&amp;#x53C8;&amp;#x65AD;&amp;#x7EBF;&amp;#x65F6;&amp;#x81EA;&amp;#x52A8;&amp;#x91CD;&amp;#x542F;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;figure class=&#34;highlight shell hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;!/bin/sh&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;ipv6 check script, reboot &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; fails&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;url=&amp;lt;an ipv6-only site&amp;gt;  || delete the &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;#&amp;quot;&lt;/span&gt; to take effect or replace &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;$url&amp;apos;&lt;/span&gt; with actual url down &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; the corresponding &lt;span class=&#34;hljs-built_in&#34;&gt;command&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;n=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;timeout=1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;check BEGIN&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ping -c $n -W $timeout $url&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if [ $? != 0 ];then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;failed, try reboot&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    reboot&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;working fine!&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;exit 0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&amp;#x811A;&amp;#x672C;&amp;#x5185;&amp;#x5BB9;&amp;#x4E00;&amp;#x76EE;&amp;#x4E86;&amp;#x7136;&amp;#xFF0C;&amp;#x9700;&amp;#x8981;&amp;#x6CE8;&amp;#x610F;&amp;#x7684;&amp;#x4E00;&amp;#x70B9;&amp;#xFF0C;&lt;code&gt;logger -t&lt;/code&gt;&amp;#x5728;log&amp;#x4E2D;&amp;#x5199;&amp;#x5165;&amp;#x4FE1;&amp;#x606F;&amp;#x65F6;&amp;#x9700;&amp;#x8981;&amp;#x4E24;&amp;#x4E2A;&amp;#x5B57;&amp;#x7B26;&amp;#x4E32;&amp;#x4F5C;&amp;#x4E3A;&amp;#x8F93;&amp;#x5165;&amp;#xFF0C;&amp;#x5982;&amp;#x4E0A;&amp;#x6587;&amp;#x7684;&amp;#x8BED;&amp;#x53E5;&amp;#x8FD0;&amp;#x884C;&amp;#x540E;&amp;#x5728;padavan&amp;#x7BA1;&amp;#x7406;&amp;#x9762;&amp;#x677F;&amp;#x7684;log&amp;#x663E;&amp;#x793A;&amp;#x5982;&amp;#x4E0B;&amp;#xFF1A;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Oct 21 17:40:00 [ipv6]:  check BEGIN&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Oct 21 17:40:03 [ipv6]:  working fine&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&amp;#x5B9E;&amp;#x9645;&amp;#x4F7F;&amp;#x7528;&amp;#x4E2D;&amp;#xFF0C;&amp;#x8FD9;&amp;#x6837;&amp;#x53EF;&amp;#x80FD;&amp;#x4F1A;&amp;#x5BFC;&amp;#x81F4;log&amp;#x680F;&amp;#x4E2D;&amp;#x7684;&amp;#x5185;&amp;#x5BB9;&amp;#x88AB;&amp;#x4EE5;&amp;#x4E0A;&amp;#x4E24;&amp;#x6761;&amp;#x5360;&amp;#x6EE1;&amp;#xFF0C;&amp;#x53EF;&amp;#x4EE5;&amp;#x5728;&amp;#x6D4B;&amp;#x8BD5;&amp;#x5B9E;&amp;#x9645;&amp;#x81EA;&amp;#x52A8;&amp;#x8FD0;&amp;#x884C;&amp;#x6B63;&amp;#x5E38;&amp;#x540E;&amp;#x5C06;log&amp;#x680F;&amp;#x8F93;&amp;#x51FA;&amp;#x5220;&amp;#x9664;&amp;#x3002;&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#cao-zuo-guo-cheng&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;cao-zuo-guo-cheng&#34;&gt;&amp;#x64CD;&amp;#x4F5C;&amp;#x8FC7;&amp;#x7A0B;&lt;/span&gt;&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;&lt;p&gt;&amp;#x52FE;&amp;#x9009;&amp;#x9AD8;&amp;#x7EA7;&amp;#x8BBE;&amp;#x7F6E;-&amp;#x7CFB;&amp;#x7EDF;&amp;#x7BA1;&amp;#x7406;-&amp;#x670D;&amp;#x52A1;-&amp;#x542F;&amp;#x7528;ssh&amp;#x670D;&amp;#x52A1;&amp;#xFF0C;windows&amp;#x53EF;&amp;#x80FD;&amp;#x4F1A;&amp;#x56E0;&amp;#x4E3A;&amp;#x7AEF;&amp;#x53E3;&amp;#x539F;&amp;#x56E0;&amp;#x65E0;&amp;#x6CD5;&amp;#x8FDE;&amp;#x63A5;&amp;#xFF0C;&amp;#x6253;&amp;#x5F00;&amp;#x5BF9;&amp;#x5E94;&amp;#x7AEF;&amp;#x53E3;&amp;#x5373;&amp;#x53EF;&lt;/p&gt;
 &lt;figure class=&#34;highlight bash hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ssh admin@192.168.123.1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&amp;#x8FDB;&amp;#x5165;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;&amp;#x540E;&amp;#xFF0C;&amp;#x8981;&amp;#x5148;&amp;#x627E;&amp;#x5230;&lt;code&gt;/etc/storage/&lt;/code&gt;&amp;#x8DEF;&amp;#x5F84;&amp;#xFF0C;&amp;#x56E0;&amp;#x4E3A;&amp;#x5176;&amp;#x4F59;&amp;#x8DEF;&amp;#x5F84;&amp;#x5728;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;&amp;#x91CD;&amp;#x542F;&amp;#x540E;&amp;#x4F1A;&amp;#x81EA;&amp;#x52A8;&amp;#x6062;&amp;#x590D;&amp;#x3002;&amp;#x811A;&amp;#x672C;&amp;#x8FD8;&amp;#x8981;&amp;#x91CD;&amp;#x590D;&amp;#x7528;&amp;#x5462;&amp;#x662F;&amp;#x5427;~&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&amp;#x76F4;&amp;#x63A5;&amp;#x7528;&lt;code&gt;vi ipv6_check.sh&lt;/code&gt;&amp;#x547D;&amp;#x4EE4;&amp;#x65B0;&amp;#x5EFA;&amp;#x811A;&amp;#x672C;&amp;#xFF0C;&amp;#x5C06;&amp;#x4E0A;&amp;#x9762;&amp;#x7684;&amp;#x5185;&amp;#x5BB9;&amp;#x8F93;&amp;#x5165;&amp;#x4FDD;&amp;#x5B58;&amp;#x9000;&amp;#x51FA;&amp;#x5373;&amp;#x53EF;&amp;#x3002;&amp;#x63D0;&amp;#x9192;&amp;#x4E00;&amp;#x4E0B;vi&amp;#x7684;&amp;#x64CD;&amp;#x4F5C;&amp;#x6700;&amp;#x597D;&amp;#x5148;&amp;#x719F;&amp;#x6089;&amp;#x719F;&amp;#x6089;&amp;#x3002;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&amp;#x7531;&amp;#x4E8E;padavan&amp;#x7CFB;&amp;#x7EDF;&amp;#x7684;&amp;#x8BBE;&amp;#x7F6E;&amp;#xFF0C;&amp;#x5982;&amp;#x679C;&amp;#x6CA1;&amp;#x6709;&amp;#x6267;&amp;#x884C;&amp;#x4FDD;&amp;#x5B58;&amp;#x811A;&amp;#x672C;&amp;#xFF0C;&amp;#x5C31;&amp;#x5E76;&amp;#x6CA1;&amp;#x6709;&amp;#x771F;&amp;#x6B63;&amp;#x7684;&amp;#x5199;&amp;#x5165;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;Rom&amp;#x91CC;&amp;#xFF0C;&amp;#x91CD;&amp;#x542F;&amp;#x4E4B;&amp;#x540E;&amp;#x6587;&amp;#x4EF6;&amp;#x8FD8;&amp;#x4F1A;&amp;#x4E22;&amp;#x5931;&amp;#x3002;&lt;br&gt; &amp;#x6267;&amp;#x884C;&lt;code&gt;/sbin/mtd_storage.sh save&lt;/code&gt;&amp;#x4FDD;&amp;#x5B58;&amp;#x914D;&amp;#x7F6E;&amp;#x3002;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&amp;#x8BBE;&amp;#x7F6E;&amp;#x5B9A;&amp;#x65F6;&amp;#x811A;&amp;#x672C;&lt;br&gt; &amp;#x7CFB;&amp;#x7EDF;&amp;#x7BA1;&amp;#x7406;-&amp;#x670D;&amp;#x52A1;-Cron&amp;#x5B88;&amp;#x62A4;&amp;#x7A0B;&amp;#x5E8F;&amp;#xFF08;&amp;#x8BA1;&amp;#x5212;&amp;#x4EFB;&amp;#x52A1;&amp;#xFF09;-Crontab&amp;#x4E2D;&amp;#x8F93;&amp;#x5165;&lt;code&gt;*/10 * * * * /etc/storage/ipv6_check.sh&lt;/code&gt;&amp;#xFF0C;&amp;#x8BBE;&amp;#x7F6E;&amp;#x6BCF;&amp;#x5341;&amp;#x5206;&amp;#x949F;&amp;#x8FD0;&amp;#x884C;&amp;#x4E00;&amp;#x6B21;&amp;#x811A;&amp;#x672C;&amp;#xFF0C;&amp;#x5927;&amp;#x529F;&amp;#x544A;&amp;#x6210;&amp;#xFF01;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;blockquote&gt;
&lt;p&gt;There&amp;apos;s a boring vacation ahead. Time to start the project.&lt;br&gt;Here: &lt;a href=&#34;https://github.com/Mocky-533/PasswordBox&#34;&gt;&lt;strong&gt;repository link&lt;/strong&gt;&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;h2&gt;&lt;a href=&#34;#intro&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;intro&#34;&gt;Intro&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;This is a mini-mini project. The functions are shown below.&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Require a key to log in&lt;/li&gt;
&lt;li&gt;Add password item&lt;ul&gt;
&lt;li&gt;App/site name&lt;/li&gt;
&lt;li&gt;Account/email address&lt;/li&gt;
&lt;li&gt;Password&lt;/li&gt;
&lt;li&gt;Adding time (auto-generate)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;Encrypt the password&lt;/li&gt;
&lt;li&gt;Store password item&lt;/li&gt;
&lt;li&gt;Search for password(s)&lt;ul&gt;
&lt;li&gt;By app/site name&lt;/li&gt;
&lt;li&gt;By account/email address&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;Update/delete password item&lt;ul&gt;
&lt;li&gt;Take password item ID as the parameter&lt;/li&gt;
&lt;li&gt;Display the password item before confirming deletion.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;Change log in key&lt;/li&gt;
&lt;li&gt;(2022.1) Generate password. First take a number as password length, and then generate a password with letters, numbers, and symbols.&lt;/li&gt;
&lt;li&gt;Use curses module to display&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;a href=&#34;#functions&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;functions&#34;&gt;Functions&lt;/span&gt;&lt;/h2&gt;&lt;h3&gt;&lt;a href=&#34;#log-in-key&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;log-in-key&#34;&gt;Log in key&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;It&amp;apos;s easy.&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;A key is demanded on the first launch. Double check, then hash it and store it in the database. Every time after that, simply input the key and verify to the main interface.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;There should be nothing poping on the screen when inputting the log in key.&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;p&gt;With &lt;code&gt;getpass&lt;/code&gt; module&amp;#xFF1A;&lt;/p&gt;
 &lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; getpass&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pwd = getpass.getpass(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;[PASSWROD]: &amp;quot;&lt;/span&gt;) &lt;span class=&#34;hljs-comment&#34;&gt;# hide input&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;With &lt;code&gt;curses.noecho()&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;a href=&#34;#python-curses-module&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;python-curses-module&#34;&gt;Python Curses Module&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;Here&amp;apos;s the &lt;a href=&#34;https://docs.python.org/3/library/curses.html&#34;&gt;official documentation&lt;/a&gt;. Simple as that.&lt;/p&gt;
&lt;h3&gt;&lt;a href=&#34;#encryption-adding-deleting-updateing-and-searching&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;encryption-adding-deleting-updateing-and-searching&#34;&gt;Encryption, Adding, Deleting, Updateing and Searching&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;Due to the non-reversibility of hashing, another encryption method is needed. Here I shift the ascii code of the charactor. The offset value is the seconds value of the adding time plus 15. For decryption, shift the ascii backwards, of course.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# offset functions&amp;#x3002; only one is enough actually, with changing offset value&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;enascii&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;num: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;, offset: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; num - offset &amp;gt;= &lt;span class=&#34;hljs-number&#34;&gt;33&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; num - offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;93&lt;/span&gt; + num - offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;deascii&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;num: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;, offset: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; num + offset &amp;lt;= &lt;span class=&#34;hljs-number&#34;&gt;126&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; num + offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; num + offset - &lt;span class=&#34;hljs-number&#34;&gt;93&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# encryption&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;encrypt&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;psw: &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;, offset: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    encrypt_num = []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; psw:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        encrypt_num.append(enascii(&lt;span class=&#34;hljs-built_in&#34;&gt;ord&lt;/span&gt;(i), offset + &lt;span class=&#34;hljs-number&#34;&gt;15&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    encrypted = [&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(a) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; a &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; encrypt_num]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join(encrypted)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# decryption, s as encrypted password string&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;decrypt&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;s: &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;, offset: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    pwd = [&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(deascii(&lt;span class=&#34;hljs-built_in&#34;&gt;ord&lt;/span&gt;(a), offset + &lt;span class=&#34;hljs-number&#34;&gt;15&lt;/span&gt;)) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; a &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; s]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join(pwd)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;I didn&amp;apos;t hide the input when adding password. Some passwords might be complicated. Input them multiple times could be a pain in the **.&lt;/p&gt;
&lt;p&gt;When adding password, the box searches for duplicated password items in the database. If there&amp;apos;s a password item with the same site/app name and account/email address, the box offers a chance to update password item rather than adding a duplication.&lt;/p&gt;
&lt;p&gt;It was hard to use Regx in sqlite3. There&amp;apos;s &lt;a href=&#34;https://stackoverflow.com/questions/5365451/problem-with-regexp-python-and-sqlite&#34;&gt;a good solution in StackOverflow&lt;/a&gt; which I found suitable for the box.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;reg = re.&lt;span class=&#34;hljs-built_in&#34;&gt;compile&lt;/span&gt;(expr, re.I)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;What&amp;apos;s left are just database operations.&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; sqlite3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db = sqlite3.connect(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;database.db&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cur = db.cursor()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cur.execute() &lt;span class=&#34;hljs-comment&#34;&gt;# commands here&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;result1 = cur.fetchall()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;result2 = cur.fetchone()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db.commit()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db.close()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create_command = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;CREATE TABLE (table) ...&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;add_command = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;INSERT INTO (table) (cols) VALUES (value)&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt; &lt;span class=&#34;hljs-comment&#34;&gt;# value must be tuple type&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;select_command = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;SELECT * FROM (table) WHERE ...&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;update_command = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;UPDATE (table) SET ... WHERE ...&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;delete_command = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&amp;quot;DELETE FROM (table) WHERE ...&amp;quot;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h2&gt;&lt;a href=&#34;#to-do&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;to-do&#34;&gt;To Do&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;Some are mentioned above. Here&amp;apos;re something else.&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;input checked disabled type=&#34;checkbox&#34;&gt; &lt;del&gt;GUI&lt;/del&gt; Used curses instead.&lt;/li&gt;
&lt;li&gt;&lt;input checked disabled type=&#34;checkbox&#34;&gt; &lt;del&gt;Use Regx when searching&lt;/del&gt; DOne&lt;/li&gt;
&lt;li&gt;&lt;input checked disabled type=&#34;checkbox&#34;&gt; &lt;del&gt;Offer a chance when adding a duplication&lt;/del&gt;&lt;/li&gt;
&lt;li&gt;&lt;input checked disabled type=&#34;checkbox&#34;&gt; &lt;del&gt;Interface optimizing&lt;/del&gt;&lt;/li&gt;
&lt;/ul&gt;

