&lt;p&gt;&amp;#x8BBE;&amp;#x7F6E;&amp;#x767B;&amp;#x9646;&amp;#x53E3;&amp;#x4EE4;&amp;#x4EE5;&amp;#x53CA;&amp;#x540E;&amp;#x7EED;&amp;#x4F7F;&amp;#x7528;&amp;#x65F6;&amp;#x8F93;&amp;#x5165;&amp;#x53E3;&amp;#x4EE4;&amp;#x9700;&amp;#x8981;&amp;#x5BF9;&amp;#x8F93;&amp;#x5165;&amp;#x5185;&amp;#x5BB9;&amp;#x8FDB;&amp;#x884C;&amp;#x9690;&amp;#x85CF;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;p&gt;&amp;#x7528;getpass&amp;#x5E93;&amp;#xFF1A;&lt;/p&gt;
