&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# offset functions&amp;#x3002; only one is enough actually, with changing offset value&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;enascii&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;num: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;, offset: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; num - offset &amp;gt;= &lt;span class=&#34;hljs-number&#34;&gt;33&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; num - offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;93&lt;/span&gt; + num - offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;deascii&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;num: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;, offset: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; num + offset &amp;lt;= &lt;span class=&#34;hljs-number&#34;&gt;126&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; num + offset&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; num + offset - &lt;span class=&#34;hljs-number&#34;&gt;93&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# encryption&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;encrypt&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;psw: &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;, offset: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    encrypt_num = []&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; psw:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        encrypt_num.append(enascii(&lt;span class=&#34;hljs-built_in&#34;&gt;ord&lt;/span&gt;(i), offset + &lt;span class=&#34;hljs-number&#34;&gt;15&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    encrypted = [&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(a) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; a &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; encrypt_num]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join(encrypted)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# decryption, s as encrypted password string&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;decrypt&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;s: &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;, offset: &lt;span class=&#34;hljs-built_in&#34;&gt;int&lt;/span&gt;&lt;/span&gt;) -&amp;gt; &lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    pwd = [&lt;span class=&#34;hljs-built_in&#34;&gt;chr&lt;/span&gt;(deascii(&lt;span class=&#34;hljs-built_in&#34;&gt;ord&lt;/span&gt;(a), offset + &lt;span class=&#34;hljs-number&#34;&gt;15&lt;/span&gt;)) &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; a &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; s]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;.join(pwd)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&amp;#x6DFB;&amp;#x52A0;&amp;#x548C;&amp;#x66F4;&amp;#x65B0;&amp;#x5BC6;&amp;#x7801;&amp;#x65F6;&amp;#x7684;&amp;#x5BC6;&amp;#x7801;&amp;#x8F93;&amp;#x5165;&amp;#x6CA1;&amp;#x6709;&amp;#x9690;&amp;#x85CF;&amp;#xFF0C;&amp;#x4E5F;&amp;#x7B97;&amp;#x662F;&amp;#x5077;&amp;#x4E2A;&amp;#x61D2;&amp;#x5427;&amp;#xFF0C;&amp;#x6BD5;&amp;#x7ADF;&amp;#x6709;&amp;#x4E9B;&amp;#x6BD4;&amp;#x8F83;&amp;#x590D;&amp;#x6742;&amp;#x7684;&amp;#x5BC6;&amp;#x7801;&amp;#x8F93;&amp;#x9519;&amp;#x4E86;&amp;#x8981;&amp;#x91CD;&amp;#x65B0;&amp;#x8F93;&amp;#x4E24;&amp;#x904D;&amp;#x751A;&amp;#x81F3;&amp;#x591A;&amp;#x904D;&amp;#x96BE;&amp;#x514D;&amp;#x4F1A;&amp;#x70E6;&amp;#x3002;&lt;/p&gt;
&lt;p&gt;&amp;#x6DFB;&amp;#x52A0;&amp;#x5BC6;&amp;#x7801;&amp;#x65F6;&amp;#xFF0C;&amp;#x5728;&amp;#x8F93;&amp;#x5165;&amp;#x7AD9;&amp;#x70B9;&amp;#x548C;&amp;#x8D26;&amp;#x6237;&amp;#x540E;&amp;#x5BF9;&amp;#x6570;&amp;#x636E;&amp;#x5E93;&amp;#x4E2D;&amp;#x5DF2;&amp;#x6709;&amp;#x6761;&amp;#x76EE;&amp;#x8FDB;&amp;#x884C;&amp;#x67E5;&amp;#x8BE2;&amp;#xFF0C;&amp;#x82E5;&amp;#x53D1;&amp;#x73B0;&amp;#x6709;&amp;#x540C;&amp;#x7AD9;&amp;#x70B9;&amp;#x540C;&amp;#x8D26;&amp;#x6237;&amp;#x5BC6;&amp;#x7801;&amp;#x6761;&amp;#x76EE;&amp;#x8BE2;&amp;#x95EE;&amp;#x662F;&amp;#x5426;&amp;#x505C;&amp;#x6B62;&amp;#x6DFB;&amp;#x52A0;&amp;#x8F6C;&amp;#x800C;&amp;#x66F4;&amp;#x65B0;&amp;#x5BC6;&amp;#x7801;&amp;#x3002;&amp;#x8FD9;&amp;#x91CC;&amp;#x5339;&amp;#x914D;&amp;#x65B9;&amp;#x5F0F;&amp;#x4E3A;&amp;#xFF1A;&amp;#x7AD9;&amp;#x70B9;&amp;#x4FE1;&amp;#x606F;&amp;#x5B8C;&amp;#x5168;&amp;#x76F8;&amp;#x540C;&amp;#xFF0C;&amp;#x8D26;&amp;#x6237;&amp;#x4FE1;&amp;#x606F;&amp;#x4E0D;&amp;#x533A;&amp;#x5206;&amp;#x5927;&amp;#x5C0F;&amp;#x3002;&lt;/p&gt;
&lt;p&gt;sqlite3&amp;#x8FDB;&amp;#x884C;&amp;#x6B63;&amp;#x5219;&amp;#x641C;&amp;#x7D22;&amp;#x9047;&amp;#x5230;&amp;#x4E86;&amp;#x70B9;&amp;#x56F0;&amp;#x96BE;&amp;#xFF0C;&amp;#x7FFB;&amp;#x4E86;&amp;#x597D;&amp;#x4E45;&amp;#x6587;&amp;#x6863;&amp;#x4E5F;&amp;#x6CA1;&amp;#x5F04;&amp;#x51FA;&amp;#x4E2A;&amp;#x65B9;&amp;#x6CD5;&amp;#xFF0C;&amp;#x6700;&amp;#x540E;&amp;#x9009;&amp;#x62E9;&amp;#x57FA;&amp;#x4E8E;&lt;a href=&#34;https://stackoverflow.com/questions/5365451/problem-with-regexp-python-and-sqlite&#34;&gt;StackOverflow&amp;#x4E2D;&amp;#x7684;&amp;#x4E00;&amp;#x4E2A;&amp;#x65B9;&amp;#x6CD5;&lt;/a&gt;&amp;#x5B8C;&amp;#x6210;&amp;#x3002;&amp;#x5BC6;&amp;#x7801;&amp;#x6761;&amp;#x76EE;&amp;#x67E5;&amp;#x8BE2;&amp;#x6B63;&amp;#x5219;&amp;#x5339;&amp;#x914D;&amp;#x8BBE;&amp;#x7F6E;&amp;#x5927;&amp;#x5C0F;&amp;#x5199;&amp;#x4E0D;&amp;#x654F;&amp;#x611F;&amp;#xFF0C;&amp;#x5373;&amp;#x5C06;&amp;#x4E0A;&amp;#x8FF0;&amp;#x89E3;&amp;#x6CD5;&amp;#x4E2D;&amp;#x6B63;&amp;#x5219;&amp;#x8868;&amp;#x8FBE;&amp;#x5F0F;&amp;#x5B9A;&amp;#x4E49;&amp;#x6539;&amp;#x4E3A;&amp;#xFF1A;&lt;/p&gt;
&lt;figure class=&#34;highlight python hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;reg = re.&lt;span class=&#34;hljs-built_in&#34;&gt;compile&lt;/span&gt;(expr, re.I)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

